css:
.loader {
  display: inline-block;
  width: 128px;
  height: 8px;
  border-radius: 999px;
  background: color-mix(in srgb, var(--loader-color) 16%, transparent);
  overflow: hidden;
}
.loader::before {
      content: "";
      display: block;
      width: 42%;
      height: 100%;
      border-radius: inherit;
      background: linear-gradient(90deg, var(--loader-color), var(--loader-secondary-color));
      animation: progressSlide 0.9s ease-in-out infinite;
    }
    @keyframes progressSlide { 0% { transform: translateX(-120%); } 100% { transform: translateX(260%); } }
